import os
import time
import secrets
from typing import Optional, Dict, Any

from fastapi import FastAPI, HTTPException, Header
from pydantic import BaseModel, Field
from web3 import Web3
from eth_account.messages import encode_defunct

app = FastAPI(title="Web3 Authentication Service")

w3 = Web3()

NONCE_TTL_SECONDS = int(os.getenv("NONCE_TTL_SECONDS", "300"))
TOKEN_TTL_SECONDS = int(os.getenv("TOKEN_TTL_SECONDS", "86400"))

nonces: Dict[str, Dict[str, Any]] = {}
sessions: Dict[str, Dict[str, Any]] = {}


def now_ts() -> int:
    return int(time.time())


def normalize_address(address: str) -> str:
    if not Web3.is_address(address):
        raise HTTPException(status_code=400, detail="Invalid Ethereum address")
    return Web3.to_checksum_address(address)


def cleanup_expired() -> None:
    current = now_ts()
    expired_nonces = [addr for addr, data in nonces.items() if data["expires_at"] <= current]
    for addr in expired_nonces:
        del nonces[addr]

    expired_sessions = [token for token, data in sessions.items() if data["expires_at"] <= current]
    for token in expired_sessions:
        del sessions[token]


def generate_nonce() -> str:
    return secrets.token_urlsafe(24)


def generate_token() -> str:
    return secrets.token_urlsafe(32)


class NonceRequest(BaseModel):
    address: str = Field(..., description="Ethereum wallet address")


class NonceResponse(BaseModel):
    address: str
    nonce: str
    message: str
    expires_at: int


class VerifyRequest(BaseModel):
    address: str = Field(..., description="Ethereum wallet address")
    signature: str = Field(..., description="Signed message signature")
    message: Optional[str] = Field(None, description="Optional full signed message")


class VerifyResponse(BaseModel):
    authenticated: bool
    address: str
    token: str
    expires_at: int


class MeResponse(BaseModel):
    authenticated: bool
    address: str
    expires_at: int


def build_sign_message(address: str, nonce: str) -> str:
    return f"Sign this message to authenticate.\nAddress: {address}\nNonce: {nonce}"


@app.get("/health")
def health() -> Dict[str, str]:
    cleanup_expired()
    return {"status": "ok"}


@app.post("/auth/nonce", response_model=NonceResponse)
def issue_nonce(payload: NonceRequest) -> NonceResponse:
    cleanup_expired()
    address = normalize_address(payload.address)
    nonce = generate_nonce()
    expires_at = now_ts() + NONCE_TTL_SECONDS
    message = build_sign_message(address, nonce)

    nonces[address] = {
        "nonce": nonce,
        "message": message,
        "expires_at": expires_at,
    }

    return NonceResponse(
        address=address,
        nonce=nonce,
        message=message,
        expires_at=expires_at,
    )


@app.post("/auth/verify", response_model=VerifyResponse)
def verify_signature(payload: VerifyRequest) -> VerifyResponse:
    cleanup_expired()
    address = normalize_address(payload.address)

    nonce_record = nonces.get(address)
    if not nonce_record:
        raise HTTPException(status_code=401, detail="No active nonce for address")

    if nonce_record["expires_at"] <= now_ts():
        del nonces[address]
        raise HTTPException(status_code=401, detail="Nonce expired")

    expected_message = nonce_record["message"]
    provided_message = payload.message or expected_message

    if provided_message != expected_message:
        raise HTTPException(status_code=401, detail="Message does not match issued nonce")

    try:
        encoded_message = encode_defunct(text=provided_message)
        recovered_address = w3.eth.account.recover_message(encoded_message, signature=payload.signature)
        recovered_address = Web3.to_checksum_address(recovered_address)
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid signature")

    if recovered_address != address:
        raise HTTPException(status_code=401, detail="Signature verification failed")

    token = generate_token()
    expires_at = now_ts() + TOKEN_TTL_SECONDS
    sessions[token] = {
        "address": address,
        "expires_at": expires_at,
    }

    del nonces[address]

    return VerifyResponse(
        authenticated=True,
        address=address,
        token=token,
        expires_at=expires_at,
    )


def get_bearer_token(authorization: Optional[str]) -> str:
    if not authorization:
        raise HTTPException(status_code=401, detail="Missing Authorization header")
    parts = authorization.split(" ", 1)
    if len(parts) != 2 or parts[0].lower() != "bearer" or not parts[1].strip():
        raise HTTPException(status_code=401, detail="Invalid Authorization header")
    return parts[1].strip()


@app.get("/auth/me", response_model=MeResponse)
def auth_me(authorization: Optional[str] = Header(None)) -> MeResponse:
    cleanup_expired()
    token = get_bearer_token(authorization)
    session = sessions.get(token)

    if not session:
        raise HTTPException(status_code=401, detail="Invalid or expired session")

    if session["expires_at"] <= now_ts():
        del sessions[token]
        raise HTTPException(status_code=401, detail="Invalid or expired session")

    return MeResponse(
        authenticated=True,
        address=session["address"],
        expires_at=session["expires_at"],
    )


@app.post("/auth/logout")
def logout(authorization: Optional[str] = Header(None)) -> Dict[str, bool]:
    cleanup_expired()
    token = get_bearer_token(authorization)
    if token in sessions:
        del sessions[token]
    return {"success": True}